## Description

End-to-end tests verifying that knowledge from past sessions is retrieved when relevant.

## Test Scenarios

### Scenario 1: Error → Gotcha Retrieval
```typescript
describe('cross-session learning', () => {
  it('retrieves gotcha when encountering similar error', async () => {
    // Session 1: Encounter and resolve error
    const session1 = await createAgentSession({ folderId });

    // Simulate error detection
    await simulateTerminalOutput(session1.id, \`
      error[E0382]: borrow of moved value: \`x\`
      --> src/main.rs:10:5
    \`);

    // Store resolution as gotcha
    await callMcpTool('sdk:note_capture', {
      type: 'gotcha',
      title: 'Rust borrow checker error',
      content: 'Clone the value or use references to avoid move'
    });

    await closeSession(session1.id);

    // Session 2: Same error should retrieve gotcha
    const session2 = await createAgentSession({ folderId });

    await simulateTerminalOutput(session2.id, \`
      error[E0382]: borrow of moved value: \`y\`
      --> src/lib.rs:25:10
    \`);

    // Check if gotcha was injected
    const contextReminder = await getLastSystemReminder(session2.id);
    expect(contextReminder).toContain('Clone the value');
  });
});
```

### Scenario 2: Pattern Reuse
```typescript
it('retrieves relevant patterns for similar tasks', async () => {
  // Session 1: Store pattern
  const session1 = await createAgentSession({ folderId });

  await callMcpTool('sdk:memory_store', {
    tier: 'long_term',
    contentType: 'pattern',
    content: 'For React forms, use controlled components with useState'
  });

  await closeSession(session1.id);

  // Session 2: Query for form implementation
  const session2 = await createAgentSession({ folderId });

  const results = await callMcpTool('sdk:memory_search', {
    query: 'implementing form in React'
  });

  expect(results.content.results).toContainEqual(
    expect.objectContaining({
      content: expect.stringContaining('controlled components')
    })
  );
});
```

### Scenario 3: Insight Application
```typescript
it('tracks insight application across sessions', async () => {
  // Create insight
  const insight = await callMcpTool('sdk:insight_extract', {
    type: 'convention',
    name: 'API naming',
    description: 'Use kebab-case for all API endpoints',
    confidence: 0.8
  });

  // Session 1: Insight applied (via context injection)
  const session1 = await createAgentSession({ folderId });

  // Mark as applied
  await callMcpTool('sdk:insight_applied', {
    insightId: insight.content.id,
    helpful: true
  });

  await closeSession(session1.id);

  // Verify confidence increased
  const updatedInsight = await getInsight(insight.content.id);
  expect(updatedInsight.confidence).toBeGreaterThan(0.8);

  // Verify application tracked
  const applications = await getInsightApplications(insight.content.id);
  expect(applications.length).toBe(1);
  expect(applications[0].helpful).toBe(true);
});
```

### Scenario 4: Multi-Session Context Building
```typescript
it('accumulates knowledge across multiple sessions', async () => {
  const sessions = [];

  // Create 5 sessions, each adding knowledge
  for (let i = 0; i < 5; i++) {
    const session = await createAgentSession({ folderId });

    await callMcpTool('sdk:memory_store', {
      tier: 'working',
      contentType: 'observation',
      content: \`Observation from session \${i}\`
    });

    await closeSession(session.id);
    sessions.push(session);
  }

  // New session should have access to accumulated knowledge
  const finalSession = await createAgentSession({ folderId });

  const results = await callMcpTool('sdk:memory_search', {
    query: 'Observation',
    limit: 50
  });

  // Should find observations from multiple sessions
  const sessionSources = new Set(results.content.results.map(r => r.sessionId));
  expect(sessionSources.size).toBeGreaterThan(1);
});
```

