## Description

Automatically generate hindsight notes when an error is followed by a resolution within a time window.

## Requirements

### Detection Logic
```typescript
interface FailureResolutionPair {
  failure: {
    timestamp: Date;
    error: DetectedError;
    context: string;  // What agent was trying to do
  };
  resolution: {
    timestamp: Date;
    commands: string[];  // Commands that fixed it
    outcome: 'success' | 'partial' | 'workaround';
  };
  duration: number;  // Seconds to resolution
}

async function detectResolution(trajectory: SessionTrajectory): FailureResolutionPair[] {
  const pairs: FailureResolutionPair[] = [];
  const errors = extractErrors(trajectory);

  for (const error of errors) {
    const resolution = findResolutionAfter(trajectory, error, {
      maxWindow: 600000,  // 10 minutes
      successPatterns: [
        /successfully/i,
        /no errors/i,
        /tests passed/i,
        /build succeeded/i
      ]
    });

    if (resolution) {
      pairs.push({ failure: error, resolution, duration: resolution.timestamp - error.timestamp });
    }
  }

  return pairs;
}
```

### Hindsight Note Format
```markdown
# Gotcha: [Error Type] in [Language]

## Problem
\`\`\`
[original error message]
\`\`\`

## Context
- File: [file path]
- Line: [line number]
- Task: [what agent was trying to do]

## Resolution
\`\`\`bash
[commands that fixed it]
\`\`\`

## Key Insight
[Extracted lesson - why this happened, how to avoid]

## Metadata
- Resolution time: [duration]
- Confidence: [based on success clarity]
- Source session: [session-id]
- Generated: [timestamp]
```

### LLM Extraction
```typescript
async function extractInsight(pair: FailureResolutionPair): string {
  return await llm.complete({
    system: "Extract a concise lesson from this error resolution",
    prompt: \`
      Error: \${pair.failure.error.message}
      Resolution: \${pair.resolution.commands.join('\\n')}

      What is the key insight? Why did this happen and how to prevent it?
    \`,
    maxTokens: 100
  });
}
```

