## Description

Compact working memory by clustering similar entries and summarizing them to reduce context size.

## Requirements

### Compaction Algorithm
```typescript
async function compactWorkingMemory(userId: string): number {
  const memories = await getWorkingMemories(userId);

  if (memories.length < COMPACTION_THRESHOLD) {
    return 0;  // Not enough to compact
  }

  // 1. Generate embeddings for all entries
  const embeddings = await Promise.all(
    memories.map(m => embeddingService.embed(m.content))
  );

  // 2. Cluster by semantic similarity
  const clusters = clusterByEmbedding(memories, embeddings, {
    threshold: 0.8,  // Cosine similarity threshold
    minClusterSize: 2
  });

  // 3. For each cluster, create summary
  let compactedCount = 0;
  for (const cluster of clusters) {
    if (cluster.length < 2) continue;

    // Summarize cluster
    const summary = await summarizeCluster(cluster);

    // Create summary entry
    await storeMemory({
      tier: 'working',
      contentType: 'summary',
      content: summary,
      metadata: {
        sourceIds: cluster.map(m => m.id),
        compactedAt: new Date()
      }
    });

    // Delete original entries
    await deleteMemories(cluster.map(m => m.id));

    compactedCount += cluster.length - 1;  // Net reduction
  }

  return compactedCount;
}
```

### Clustering Implementation
```typescript
function clusterByEmbedding(
  memories: Memory[],
  embeddings: Embedding[],
  options: { threshold: number; minClusterSize: number }
): Memory[][] {
  const clusters: Memory[][] = [];
  const assigned = new Set<string>();

  for (let i = 0; i < memories.length; i++) {
    if (assigned.has(memories[i].id)) continue;

    const cluster = [memories[i]];
    assigned.add(memories[i].id);

    for (let j = i + 1; j < memories.length; j++) {
      if (assigned.has(memories[j].id)) continue;

      const similarity = cosineSimilarity(embeddings[i], embeddings[j]);
      if (similarity >= options.threshold) {
        cluster.push(memories[j]);
        assigned.add(memories[j].id);
      }
    }

    if (cluster.length >= options.minClusterSize) {
      clusters.push(cluster);
    }
  }

  return clusters;
}
```

### Summarization
```typescript
async function summarizeCluster(cluster: Memory[]): string {
  const contents = cluster.map(m => m.content).join('\n---\n');

  return await llm.complete({
    system: "Summarize these related observations into a single, actionable memory.",
    prompt: contents,
    maxTokens: 200
  });
}
```

