### Scenario 1: Basic Session Lifecycle
```typescript
describe('session lifecycle', () => {
  it('preserves memories across sessions', async () => {
    // Session 1: Create and store memories
    const session1 = await createAgentSession({ folderId });

    await callMcpTool('sdk:memory_store', {
      tier: 'working',
      contentType: 'observation',
      content: 'Important observation from session 1'
    }, { sessionId: session1.id });

    await closeSession(session1.id);

    // Session 2: Verify memory available
