### Scenario 3: Memory Promotion on Session Close
```typescript
it('promotes valuable working memories on session close', async () => {
  const session = await createAgentSession({ folderId });

  // Store working memory with high confidence
  const memory = await callMcpTool('sdk:memory_store', {
    tier: 'working',
    contentType: 'pattern',
    content: 'Discovered pattern',
    confidence: 0.9
  });

  // Simulate access (increases accessCount)
  await callMcpTool('sdk:memory_search', { query: 'Discovered pattern' });
  await callMcpTool('sdk:memory_search', { query: 'Discovered pattern' });
  await callMcpTool('sdk:memory_search', { query: 'Discovered pattern' });

  await closeSession(session.id);

  // Verify promotion
  const promoted = await getMemory(memory.content.id);
  expect(promoted.tier).toBe('long_term');
});
```

### Scenario 4: Folder Inheritance
```typescript
