## Description

Create a scheduled job that runs memory consolidation periodically (default: every 4 hours).

## Requirements

### Scheduler Implementation
```typescript
class ConsolidationScheduler {
  private interval: NodeJS.Timeout | null = null;
  private isRunning = false;

  start(intervalMs: number = 4 * 60 * 60 * 1000) {  // 4 hours
    if (this.interval) return;

    this.interval = setInterval(() => this.runConsolidation(), intervalMs);
    console.log('[Consolidation] Scheduler started');
  }

  stop() {
    if (this.interval) {
      clearInterval(this.interval);
      this.interval = null;
    }
  }

  async runConsolidation() {
    if (this.isRunning) {
      console.log('[Consolidation] Skipping - already running');
      return;
    }

    this.isRunning = true;
    try {
      const result = await consolidateAllUsers();
      console.log('[Consolidation] Complete:', result);
    } finally {
      this.isRunning = false;
    }
  }
}
```

### Consolidation Steps
```typescript
async function consolidateAllUsers(): ConsolidationResult {
  const users = await getActiveUsers();
  const results = {
    expiredCleaned: 0,
    promoted: 0,
    demoted: 0,
    compacted: 0,
    embeddingsGenerated: 0
  };

  for (const userId of users) {
    // 1. Cleanup expired
    results.expiredCleaned += await cleanupExpiredMemories(userId);

    // 2. Promote high-value working → long-term
    results.promoted += await promoteWorkingToLongTerm(userId);

    // 3. Demote stale long-term → working
    results.demoted += await demoteStaleLongTerm(userId);

    // 4. Compact working memory
    results.compacted += await compactWorkingMemory(userId);

    // 5. Generate missing embeddings
    results.embeddingsGenerated += await generateMissingEmbeddings(userId);
  }

  return results;
}
```

### Configuration
```typescript
interface ConsolidationConfig {
  intervalMs: number;          // Default: 4 hours
  promotionThreshold: {
    minConfidence: number;     // Default: 0.8
    minAccessCount: number;    // Default: 3
  };
  demotionThreshold: {
    maxDaysSinceAccess: number; // Default: 90
    maxRelevance: number;      // Default: 0.3
  };
  compactionThreshold: {
    maxWorkingEntries: number; // Default: 50
    similarityThreshold: number; // Default: 0.8
  };
}
```

