### Confidence Adjustment
```typescript
function adjustInsightConfidence(insight: Insight): number {
  const applications = await getApplications(insight.id);

  const positiveCount = applications.filter(a => a.outcome?.helpful).length;
  const negativeCount = applications.filter(a => a.outcome?.helpful === false).length;
  const totalWithFeedback = positiveCount + negativeCount;

  if (totalWithFeedback === 0) return insight.confidence;

  const feedbackRatio = positiveCount / totalWithFeedback;
  const weight = Math.min(totalWithFeedback / 10, 1);  // Cap at 10 feedback

  return insight.confidence * (1 - weight) + feedbackRatio * weight;
}
```

