// .claude/hooks/compact.mjs
// Triggered by SessionStart:compact event

export default async function onCompaction(event) {
  const { sessionId, folderId, compactionReason } = event;

  // 1. Retrieve preserved working context
  const workingContext = await getWorkingMemories(sessionId);

  // 2. Get task goals and open TODOs
  const taskContext = await getTaskContext(sessionId);

