## Description

Apply time-based relevance decay to memories that haven't been accessed, allowing stale entries to be pruned.

## Requirements

### Decay Formula
```typescript
function calculateDecayedRelevance(memory: Memory): number {
  const daysSinceAccess = daysSince(memory.lastAccessedAt || memory.createdAt);
  const originalRelevance = memory.relevance || 0.5;

  // No decay for first 7 days
  if (daysSinceAccess <= 7) {
    return originalRelevance;
  }

  // Logarithmic decay after 7 days
  // Half-life: 30 days (relevance halves every 30 days of inactivity)
  const decayFactor = Math.pow(0.5, (daysSinceAccess - 7) / 30);

  // Apply tier-specific floor
  const floor = {
    'long_term': 0.3,    // Long-term memories don't decay below 0.3
    'working': 0.1,      // Working memories can decay to 0.1
    'short_term': 0.0    // Short-term can decay to 0
  }[memory.tier] || 0.1;

  return Math.max(floor, originalRelevance * decayFactor);
}
```

### Batch Decay Application
```typescript
async function applyRelevanceDecay(userId: string): number {
  const memories = await getAllMemories(userId);
  let updated = 0;

  for (const memory of memories) {
    const newRelevance = calculateDecayedRelevance(memory);

    if (Math.abs(newRelevance - memory.relevance) > 0.01) {
      await updateMemory(memory.id, { relevance: newRelevance });
      updated++;
    }
  }

  return updated;
}
```

### Access Boost
When a memory is accessed, boost relevance:
```typescript
async function touchMemory(memoryId: string) {
  const memory = await getMemory(memoryId);

  // Boost relevance on access
  const boostedRelevance = Math.min(1.0, memory.relevance + 0.1);

  await updateMemory(memoryId, {
    relevance: boostedRelevance,
    accessCount: memory.accessCount + 1,
    lastAccessedAt: new Date()
  });
}
```

### Configuration
```typescript
interface DecayConfig {
  gracePeriodDays: number;    // Default: 7
  halfLifeDays: number;       // Default: 30
  tierFloors: {
    long_term: number;        // Default: 0.3
    working: number;          // Default: 0.1
    short_term: number;       // Default: 0.0
  };
  accessBoost: number;        // Default: 0.1
}
```

