## Description

Create the core service that watches session trajectories and extracts learnings asynchronously.

## Architecture

```typescript
class TrajectoryDistillationService {
  private trajectories = new Map<string, SessionTrajectory>();

  // Subscribe to session events
  async watchSession(sessionId: string) {
    const trajectory = new SessionTrajectory(sessionId);
    this.trajectories.set(sessionId, trajectory);

    // Subscribe to scrollback updates
    scrollbackMonitor.on('update', (sessionId, content) => {
      this.appendToTrajectory(sessionId, content);
    });

    // Periodic distillation (every 5 minutes)
    setInterval(() => this.distillCheckpoint(sessionId), 300000);
  }

  // Append scrollback chunk to trajectory
  private appendToTrajectory(sessionId: string, content: string) {
    const trajectory = this.trajectories.get(sessionId);
    if (trajectory) {
      trajectory.append(content);
    }
  }

  // Checkpoint distillation
  private async distillCheckpoint(sessionId: string) {
    const trajectory = this.trajectories.get(sessionId);
    if (!trajectory || trajectory.isEmpty()) return;

    const learnings = await this.extractLearnings(trajectory);
    await this.storeLearnings(learnings);
    trajectory.markDistilled();
  }

  // Full distillation on session end
  async onSessionEnd(sessionId: string) {
    const trajectory = this.trajectories.get(sessionId);
    if (!trajectory) return;

    const learnings = await this.extractLearnings(trajectory, { full: true });
    await this.storeLearnings(learnings);

    this.trajectories.delete(sessionId);
  }
}
```

## Trajectory Structure

```typescript
interface SessionTrajectory {
  sessionId: string;
  startedAt: Date;
  chunks: TrajectoryChunk[];
  distilledUpTo: number;  // Index of last distilled chunk
}

interface TrajectoryChunk {
  timestamp: Date;
  content: string;
  type: 'command' | 'output' | 'error' | 'file_edit';
}
```

