## Description

Track key decisions made during sessions to understand why agents chose certain approaches.

## Requirements

### Decision Detection Patterns
```typescript
const decisionPatterns = [
  // Explicit choice language
  /I('ll| will) (use|go with|choose|try) (.+?) (instead of|rather than|over) (.+)/i,
  /choosing (.+?) because/i,
  /decided to (.+?) since/i,

  // Alternative consideration
  /could (also |)(use|try) (.+?) but/i,
  /another option (is|would be) (.+)/i,

  // Trade-off language
  /trade-?off between (.+?) and (.+)/i,
  /pros and cons/i
];

interface TrackedDecision {
  timestamp: Date;
  choice: string;
  alternatives: string[];
  rationale: string | null;
  context: string;  // Surrounding text
}
```

### Extraction Logic
```typescript
async function extractDecisions(trajectory: SessionTrajectory): TrackedDecision[] {
  const decisions: TrackedDecision[] = [];

  for (const chunk of trajectory.chunks) {
    for (const pattern of decisionPatterns) {
      const match = chunk.content.match(pattern);
      if (match) {
        decisions.push({
          timestamp: chunk.timestamp,
          choice: match[3] || match[1],
          alternatives: extractAlternatives(match),
          rationale: extractRationale(chunk.content, match),
          context: chunk.content.slice(Math.max(0, match.index - 200), match.index + 200)
        });
      }
    }
  }

  return decisions;
}
```

### Storage
Store as working memory with potential for long-term promotion:
```typescript
await storeMemory({
  tier: 'working',
  contentType: 'decision',
  content: formatDecision(decision),
  metadata: {
    choice: decision.choice,
    alternatives: decision.alternatives,
    rationale: decision.rationale
  }
});
```

